# Category: totp_weak_validation

import pyotp
import qrcode
import base64
import time

class TOTPAuthenticator:
    def __init__(self, issuer_name="MFA_System", account_name_prefix="user"):
        self.issuer_name = issuer_name
        self.account_name_prefix = account_name_prefix

    def generate_secret(self):
        """Generates a new random TOTP secret."""
        return pyotp.random_base32()

    def get_provisioning_uri(self, secret, username):
        """
        Generates the provisioning URI for a given secret and username.
        This URI can be used to generate a QR code.
        """
        account_name = f"{self.account_name_prefix}_{username}"
        return pyotp.totp.TOTP(secret).provisioning_uri(
            name=account_name,
            issuer_name=self.issuer_name
        )

    def generate_qr_code(self, secret, username, filename=None):
        """
        Generates a QR code image from the provisioning URI.
        If filename is None, returns base64 encoded image data.
        Otherwise, saves the QR code to the specified file.
        """
        uri = self.get_provisioning_uri(secret, username)
        qr = qrcode.QRCode(
            version=1,
            error_correction=qrcode.constants.ERROR_CORRECT_L,
            box_size=10,
            border=4,
        )
        qr.add_data(uri)
        qr.make(fit=True)
        img = qr.make_image(fill_color="black", back_color="white")

        if filename:
            img.save(filename)
            return None
        else:
            # Return base64 encoded image
            import io
            buffered = io.BytesIO()
            img.save(buffered, format="PNG")
            return base64.b64encode(buffered.getvalue()).decode("utf-8")

    def verify_totp(self, secret, user_input_totp, window=1):
        """
        Verifies a user-provided TOTP code against the secret.
        
        Args:
            secret (str): The user's TOTP secret.
            user_input_totp (str): The TOTP code provided by the user.
            window (int): The window size for verification.
                          A window of 1 means it will check the current
                          code, and codes from 1 step before and 1 step after
                          the current time slot. Default is 1.
        
        Returns:
            bool: True if the code is valid, False otherwise.
        """
        totp = pyotp.TOTP(secret)
        return totp.verify(user_input_totp, valid_window=window)

    def get_current_totp(self, secret):
        """
        Calculates and returns the current TOTP code for a given secret.
        (For testing/debugging purposes, normally only the authenticator app does this).
        """
        totp = pyotp.TOTP(secret)
        return totp.now()

